create table public.mexal_automation_rules (id uuid primary key default gen_random_uuid(), name text not null, automation_type text not null, trigger_type text not null, enabled boolean not null default false, frequency_type text, timezone text not null default 'Europe/Rome', action_chain jsonb not null default '[]'::jsonb, configuration jsonb not null default '{}'::jsonb, last_run_at timestamptz, next_run_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.mexal_automation_runs (id uuid primary key default gen_random_uuid(), automation_rule_id uuid references public.mexal_automation_rules(id), trigger_type text, status text not null, current_action text, processed_actions integer not null default 0, failed_actions integer not null default 0, result jsonb, error_message text, started_at timestamptz not null default now(), completed_at timestamptz);
create table public.mexal_automation_action_runs (id uuid primary key default gen_random_uuid(), automation_run_id uuid not null references public.mexal_automation_runs(id) on delete cascade, action_type text not null, action_order integer not null, status text not null, result jsonb, error_message text, idempotency_key text not null unique, started_at timestamptz, completed_at timestamptz);
create index mexal_automation_rules_due_idx on public.mexal_automation_rules(next_run_at) where enabled;
create index mexal_automation_runs_started_idx on public.mexal_automation_runs(started_at desc);
create index mexal_automation_action_runs_run_idx on public.mexal_automation_action_runs(automation_run_id, action_order);
alter table public.mexal_automation_rules enable row level security; alter table public.mexal_automation_runs enable row level security; alter table public.mexal_automation_action_runs enable row level security;
create policy "authenticated read automation rules" on public.mexal_automation_rules for select to authenticated using (true);
create policy "authenticated read automation runs" on public.mexal_automation_runs for select to authenticated using (true);
create policy "authenticated read automation action runs" on public.mexal_automation_action_runs for select to authenticated using (true);
